INSERT OR IGNORE INTO LocalizedText 
        (Language,  Tag,                                  Text) 
VALUES  ('en_US',   'LOC_TOT_EVENT_NYGUITA_ARGENTINA_A_STORYTITLE', 'The Call of the Land'),
        ('en_US',   'LOC_TOT_EVENT_NYGUITA_ARGENTINA_A_COMPLETION', "The Argentinian settler stopped, after months of riding almost randomly through the wilderness. There was an inate desire to go beyond the familliar shore he always lived in. The horse suddenly runs away, as if chasing a bird. As the settler falls on the grassy ground, an unknown feeling takes them into laughter. A mix between joy, fear and excitement: is this real freedom?"),
        ('en_US',   'LOC_TOT_EVENT_NYGUITA_ARGENTINA_B_NAME', "The treasure of the land is ours to take."),
        ('en_US',   'LOC_TOT_EVENT_NYGUITA_ARGENTINA_C_NAME', "Where nature takes roots, man can too."),
        ('en_US',   'LOC_TOT_EVENT_NYGUITA_ARGENTINA_B_DESCRIPTION', "{1_Reward}."),
        ('en_US',   'LOC_TOT_EVENT_NYGUITA_ARGENTINA_C_DESCRIPTION', "{1_Reward}.");